 1→import React from "react";
 2→import { TransitionSeries } from "@remotion/transitions";
 3→import { fade } from "@remotion/transitions/fade";
 4→import { slide } from "@remotion/transitions/slide";
 5→import { wipe } from "@remotion/transitions/wipe";
 6→import { flip } from "@remotion/transitions/flip";
 7→import { springTiming } from "@remotion/transitions";
 8→import type { TransitionType } from "../types";
 9→
10→export interface SlideTransitionProps {
11→  type?: TransitionType;
12→  durationInFrames?: number;
13→  children: React.ReactNode[];
14→  slideDurations: number[];
15→}
16→
17→function getPresentation(type: TransitionType) {
18→  switch (type) {
19→    case "fade":
20→      return fade();
21→    case "slide":
22→      return slide();
23→    case "wipe":
24→      return wipe();
25→    case "flip":
26→      return flip();
27→    default:
28→      return fade();
29→  }
30→}
31→
32→export const SlideTransition: React.FC<SlideTransitionProps> = ({
33→  type = "fade",
34→  durationInFrames = 15,
35→  children,
36→  slideDurations,
37→}) => {
38→  const presentation = getPresentation(type);
39→  const timing = springTiming({ durationInFrames });
40→
41→  return (
42→    <TransitionSeries>
43→      {React.Children.map(children, (child, index) => (
44→        <React.Fragment key={index}>
45→          <TransitionSeries.Sequence
46→            durationInFrames={slideDurations[index] ?? 90}
47→          >
48→            {child}
49→          </TransitionSeries.Sequence>
50→          {index < React.Children.count(children) - 1 && (
51→            <TransitionSeries.Transition
52→              presentation={presentation}
53→              timing={timing}
54→            />
55→          )}
56→        </React.Fragment>
57→      ))}
58→    </TransitionSeries>
59→  );
60→};
