 3→/**
 4→ * Resolve an asset path. Supports:
 5→ * - Absolute paths (returned as-is)
 6→ * - HTTP URLs (returned as-is)
 7→ * - Relative paths prefixed with public/ (resolved via staticFile)
 8→ * - All other paths (resolved relative to assets/)
 9→ */
10→export function useAsset(path: string | undefined): string | undefined {
11→  if (!path) return undefined;
12→  if (path.startsWith("/") || path.startsWith("http")) return path;
13→  if (path.startsWith("public/")) return staticFile(path.replace("public/", ""));
14→  return staticFile(`../assets/${path}`);
15→}
