17→function getPresentation(type: TransitionType) {
18→  switch (type) {
19→    case "fade":
20→      return fade();
21→    case "slide":
22→      return slide();
23→    case "wipe":
24→      return wipe();
25→    case "flip":
26→      return flip();
27→    default:
28→      return fade();
29→  }
30→}
