 1→/**
 2→ * Convert seconds to frames at a given fps.
 3→ */
 4→export function secondsToFrames(seconds: number, fps: number): number {
 5→  return Math.round(seconds * fps);
 6→}
 7→
 8→/**
 9→ * Convert frames to seconds at a given fps.
10→ */
11→export function framesToSeconds(frames: number, fps: number): number {
12→  return frames / fps;
13→}
14→
15→/**
16→ * Calculate total duration in frames from an array of per-slide durations.
17→ */
18→export function totalFrames(
19→  slideDurations: number[],
20→  fps: number,
21→  transitionOverlapFrames: number = 0,
22→): number {
23→  const totalSlideFrames = slideDurations.reduce(
24→    (sum, d) => sum + secondsToFrames(d, fps),
25→    0,
26→  );
27→  const overlapReduction =
28→    Math.max(0, slideDurations.length - 1) * transitionOverlapFrames;
29→  return totalSlideFrames - overlapReduction;
30→}
31→
32→/**
33→ * Get the start frame for slide N, accounting for transition overlaps.
34→ */
35→export function slideStartFrame(
36→  slideIndex: number,
37→  durationPerSlide: number,
38→  fps: number,
39→  transitionOverlapFrames: number = 0,
40→): number {
41→  const framesPerSlide = secondsToFrames(durationPerSlide, fps);
42→  return slideIndex * (framesPerSlide - transitionOverlapFrames);
43→}
