 1→/**
 2→ * Parse hex color to RGB components.
 3→ */
 4→export function hexToRgb(hex: string): { r: number; g: number; b: number } {
 5→  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
 6→  if (!result) throw new Error(`Invalid hex color: ${hex}`);
 7→  return {
 8→    r: parseInt(result[1], 16),
 9→    g: parseInt(result[2], 16),
10→    b: parseInt(result[3], 16),
11→  };
12→}
13→
14→/**
15→ * Convert RGB to hex string.
16→ */
17→export function rgbToHex(r: number, g: number, b: number): string {
18→  return `#${[r, g, b].map((x) => x.toString(16).padStart(2, "0")).join("")}`;
19→}
20→
21→/**
22→ * Darken a hex color by a percentage (0-1).
23→ */
24→export function darken(hex: string, amount: number): string {
25→  const { r, g, b } = hexToRgb(hex);
26→  return rgbToHex(
27→    Math.round(r * (1 - amount)),
28→    Math.round(g * (1 - amount)),
29→    Math.round(b * (1 - amount)),
30→  );
31→}
32→
33→/**
34→ * Lighten a hex color by a percentage (0-1).
35→ */
36→export function lighten(hex: string, amount: number): string {
37→  const { r, g, b } = hexToRgb(hex);
38→  return rgbToHex(
39→    Math.round(r + (255 - r) * amount),
40→    Math.round(g + (255 - g) * amount),
41→    Math.round(b + (255 - b) * amount),
42→  );
43→}
44→
45→/**
46→ * Get a contrasting text color (black or white) for a given background.
47→ */
48→export function contrastText(backgroundHex: string): string {
49→  const { r, g, b } = hexToRgb(backgroundHex);
50→  const luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255;
51→  return luminance > 0.5 ? "#000000" : "#FFFFFF";
52→}
