import React from "react";
import {
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  Audio,
  AbsoluteFill,
} from "remotion";
import { TextOverlay } from "../components/TextOverlay";
import { Logo } from "../components/Logo";
import { SlideTransition } from "../components/SlideTransition";
import { NumberCounter } from "../components/NumberCounter";
import { ProgressBar } from "../components/ProgressBar";
import { useBrandKit } from "../hooks/useBrandKit";
import { useAsset } from "../hooks/useAsset";
import type { BrandKit, TransitionType } from "../types";
import { secondsToFrames } from "../lib/timing";

export interface SocialListicleProps {
  title: string;
  items: Array<{ number: number; text: string; icon?: string }>;
  brandKit?: Partial<BrandKit>;
  music?: string;
  durationPerItem?: number;
  transition?: TransitionType;
}

export const SocialListicle: React.FC<SocialListicleProps> = ({
  title,
  items,
  brandKit: brandKitProp,
  music,
  durationPerItem = 3,
  transition = "slide",
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const brand = useBrandKit(brandKitProp);
  const musicSrc = music ? useAsset(music) : undefined;
  const logoSrc = useAsset(brand.logo.primary);

  const titleFrames = secondsToFrames(1.5, fps);
  const itemFrames = secondsToFrames(durationPerItem, fps);
  const closingFrames = secondsToFrames(2, fps);

  const slideChildren: React.ReactNode[] = [];
  const slideDurations: number[] = [];

  // Title slide
  slideChildren.push(
    <AbsoluteFill
      key="title"
      style={{
        backgroundColor: brand.colors.background,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 60,
      }}
    >
      <TextOverlay
        text={title}
        fontSize={72}
        fontFamily={brand.fonts.heading}
        color={brand.colors.text}
        animationType="slide-up"
        bold
      />
    </AbsoluteFill>,
  );
  slideDurations.push(titleFrames);

  // Item slides
  items.forEach((item, i) => {
    slideChildren.push(
      <AbsoluteFill
        key={`item-${i}`}
        style={{
          backgroundColor: brand.colors.background,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          padding: 80,
          gap: 40,
        }}
      >
        {item.icon && (
          <div
            style={{
              fontSize: 80,
              marginBottom: 10,
            }}
          >
            {item.icon}
          </div>
        )}
        <NumberCounter
          from={0}
          to={item.number}
          fontSize={120}
          color={brand.colors.accent}
          fontFamily={brand.fonts.heading}
          durationFrames={20}
        />
        <TextOverlay
          text={item.text}
          fontSize={44}
          fontFamily={brand.fonts.body}
          color={brand.colors.text}
          enterFrame={10}
          animationType="slide-up"
        />
      </AbsoluteFill>,
    );
    slideDurations.push(itemFrames);
  });

  // Closing logo slide
  if (logoSrc) {
    slideChildren.push(
      <AbsoluteFill
        key="closing"
        style={{
          backgroundColor: brand.colors.background,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <Logo src={logoSrc} width={200} position="center" enterFrame={0} />
      </AbsoluteFill>,
    );
    slideDurations.push(closingFrames);
  }

  return (
    <AbsoluteFill>
      <SlideTransition
        type={transition}
        durationInFrames={15}
        slideDurations={slideDurations}
      >
        {slideChildren}
      </SlideTransition>
      <ProgressBar color={brand.colors.accent} />
      {musicSrc && <Audio src={musicSrc} volume={0.3} />}
    </AbsoluteFill>
  );
};

export const calculateMetadata = async ({
  props,
}: {
  props: SocialListicleProps;
  defaultProps: SocialListicleProps;
}): Promise<{
  durationInFrames: number;
  fps: number;
  width: number;
  height: number;
}> => {
  const fps = 30;
  const durationPerItem = props.durationPerItem ?? 3;
  const totalSeconds = 1.5 + props.items.length * durationPerItem + 2;
  const durationInFrames = secondsToFrames(totalSeconds, fps);
  return { durationInFrames, fps, width: 1080, height: 1920 };
};

export const defaultProps: SocialListicleProps = {
  title: "5 Tips for Productivity",
  items: [
    { number: 1, text: "Start your day with a clear plan" },
    { number: 2, text: "Use time-blocking for deep work" },
    { number: 3, text: "Take regular breaks to recharge" },
    { number: 4, text: "Batch similar tasks together" },
    { number: 5, text: "Review and reflect each evening" },
  ],
  durationPerItem: 3,
  transition: "slide",
};

import React from "react";
import {
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  AbsoluteFill,
  Sequence,
  Audio,
  Img,
} from "remotion";
import { TextOverlay } from "../components/TextOverlay";
import { Logo } from "../components/Logo";
import { LowerThird } from "../components/LowerThird";
import { ProgressBar } from "../components/ProgressBar";
import { SlideTransition } from "../components/SlideTransition";
import { useBrandKit, brandAsset } from "../hooks/useBrandKit";
import { useAsset } from "../hooks/useAsset";
import { secondsToFrames } from "../lib/timing";
import type { BrandKit, TransitionType } from "../types";

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

interface Section {
  heading: string;
  body: string;
  icon?: string;
}

export interface ExplainerProps {
  title: string;
  sections: Section[];
  brandKit?: Partial<BrandKit>;
  music?: string;
  durationPerSection?: number; // seconds, default 6
  transition?: TransitionType;
}

// ---------------------------------------------------------------------------
// Defaults & metadata
// ---------------------------------------------------------------------------

export const defaultProps: ExplainerProps = {
  title: "How It Works",
  sections: [
    { heading: "Connect", body: "Link your accounts in one click.", icon: undefined },
    { heading: "Automate", body: "Set up rules that run while you sleep.", icon: undefined },
    { heading: "Grow", body: "Watch your metrics climb every week.", icon: undefined },
  ],
  music: undefined,
  durationPerSection: 6,
  transition: "fade",
};

export const calculateMetadata = ({
  props,
}: {
  props: ExplainerProps;
}) => {
  const secDur = props.durationPerSection ?? 6;
  const totalSeconds = 3 + props.sections.length * secDur + 3;
  return {
    durationInFrames: totalSeconds * 30,
    fps: 30,
    width: 1920,
    height: 1080,
  };
};

// ---------------------------------------------------------------------------
// Slide sub-components
// ---------------------------------------------------------------------------

const IntroSlide: React.FC<{
  title: string;
  logoSrc: string;
  brand: ReturnType<typeof useBrandKit>;
}> = ({ title, logoSrc, brand }) => (
  <AbsoluteFill
    style={{
      background: `linear-gradient(135deg, ${brand.colors.primary}, ${brand.colors.secondary})`,
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
    }}
  >
    <TextOverlay
      text={title}
      fontSize={64}
      color={brand.colors.text}
      animationType="slide-up"
      enterFrame={5}
      bold
    />
    <div style={{ marginTop: 32 }}>
      <Logo src={logoSrc} position="center" width={100} enterFrame={20} />
    </div>
  </AbsoluteFill>
);

const SectionSlide: React.FC<{
  section: Section;
  index: number;
  total: number;
  brand: ReturnType<typeof useBrandKit>;
}> = ({ section, index, total, brand }) => {
  const frame = useCurrentFrame();
  const iconSrc = useAsset(section.icon);

  const iconOpacity = iconSrc
    ? interpolate(frame, [10, 25], [0, 1], {
        extrapolateRight: "clamp",
        extrapolateLeft: "clamp",
      })
    : 0;

  return (
    <AbsoluteFill
      style={{
        background: brand.colors.background,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: "0 120px",
      }}
    >
      {/* Optional icon */}
      {iconSrc && (
        <div style={{ opacity: iconOpacity, marginBottom: 24 }}>
          <Img src={iconSrc} style={{ width: 80, height: 80 }} />
        </div>
      )}

      {/* Section heading */}
      <TextOverlay
        text={section.heading}
        fontSize={48}
        color={brand.colors.text}
        animationType="slide-up"
        enterFrame={5}
        bold
      />

      {/* Section body */}
      <div style={{ marginTop: 20, maxWidth: 900, textAlign: "center" }}>
        <TextOverlay
          text={section.body}
          fontSize={28}
          color={brand.colors.text}
          animationType="fade"
          enterFrame={18}
        />
      </div>

      {/* Section counter (LowerThird) */}
      <LowerThird
        name={`${index + 1}/${total}`}
        title=""
        backgroundColor={brand.colors.primary}
        textColor={brand.colors.text}
        enterFrame={8}
      />
    </AbsoluteFill>
  );
};

const ClosingSlide: React.FC<{
  logoSrc: string;
  brand: ReturnType<typeof useBrandKit>;
}> = ({ logoSrc, brand }) => (
  <AbsoluteFill
    style={{
      background: `linear-gradient(135deg, ${brand.colors.primary}, ${brand.colors.secondary})`,
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
    }}
  >
    <Logo src={logoSrc} position="center" width={140} enterFrame={0} />
    <div style={{ position: "absolute", bottom: 140 }}>
      <TextOverlay
        text="Thank you"
        fontSize={36}
        color={brand.colors.text}
        animationType="fade"
        enterFrame={10}
      />
    </div>
  </AbsoluteFill>
);

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------

export const Explainer: React.FC<ExplainerProps> = ({
  title,
  sections,
  brandKit: brandKitProp,
  music,
  durationPerSection = 6,
  transition = "fade",
}) => {
  const { fps } = useVideoConfig();
  const brand = useBrandKit(brandKitProp);
  const musicSrc = useAsset(music);
  const logoSrc = brandAsset(brand.logo.primary);

  const introFrames = secondsToFrames(3, fps);
  const sectionFrames = secondsToFrames(durationPerSection, fps);
  const closingFrames = secondsToFrames(3, fps);

  // Build slide durations array for SlideTransition
  const slideDurations = [
    introFrames,
    ...sections.map(() => sectionFrames),
    closingFrames,
  ];

  return (
    <AbsoluteFill style={{ backgroundColor: brand.colors.background }}>
      {musicSrc && <Audio src={musicSrc} volume={0.25} />}

      <SlideTransition
        type={transition}
        durationInFrames={15}
        slideDurations={slideDurations}
      >
        {/* Intro */}
        <IntroSlide title={title} logoSrc={logoSrc} brand={brand} />

        {/* Sections */}
        {sections.map((section, idx) => (
          <SectionSlide
            key={idx}
            section={section}
            index={idx}
            total={sections.length}
            brand={brand}
          />
        ))}

        {/* Closing */}
        <ClosingSlide logoSrc={logoSrc} brand={brand} />
      </SlideTransition>

      {/* Progress bar throughout */}
      <ProgressBar color={brand.colors.accent} />
    </AbsoluteFill>
  );
};

import React from "react";
import {
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  Audio,
  Img,
  Sequence,
  AbsoluteFill,
} from "remotion";
import { TextOverlay } from "../components/TextOverlay";
import { Logo } from "../components/Logo";
import { ProgressBar } from "../components/ProgressBar";
import { useBrandKit } from "../hooks/useBrandKit";
import { useAsset } from "../hooks/useAsset";
import type { BrandKit } from "../types";
import { secondsToFrames } from "../lib/timing";

export interface SocialBeforeAfterProps {
  before: { label: string; image: string; description?: string };
  after: { label: string; image: string; description?: string };
  title?: string;
  brandKit?: Partial<BrandKit>;
  music?: string;
  duration?: number;
}

export const SocialBeforeAfter: React.FC<SocialBeforeAfterProps> = ({
  before,
  after,
  title,
  brandKit: brandKitProp,
  music,
  duration = 10,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const brand = useBrandKit(brandKitProp);
  const musicSrc = music ? useAsset(music) : undefined;
  const logoSrc = useAsset(brand.logo.primary);
  const beforeImgSrc = useAsset(before.image);
  const afterImgSrc = useAsset(after.image);

  const titleFrames = title ? secondsToFrames(1.5, fps) : 0;
  const beforeFrames = secondsToFrames(3, fps);
  const wipeFrames = secondsToFrames(1, fps);
  const afterFrames = secondsToFrames(3, fps);
  const comparisonFrames = secondsToFrames(2, fps);

  let offset = 0;
  const titleStart = 0;
  offset += titleFrames;

  const beforeStart = offset;
  offset += beforeFrames;

  const wipeStart = offset;
  offset += wipeFrames;

  const afterStart = offset;
  offset += afterFrames;

  const comparisonStart = offset;

  return (
    <AbsoluteFill style={{ backgroundColor: brand.colors.background }}>
      {/* Title slide */}
      {title && (
        <Sequence from={titleStart} durationInFrames={titleFrames}>
          <AbsoluteFill
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              padding: 60,
            }}
          >
            <TextOverlay
              text={title}
              fontSize={64}
              fontFamily={brand.fonts.heading}
              color={brand.colors.text}
              animationType="slide-up"
              bold
            />
          </AbsoluteFill>
        </Sequence>
      )}

      {/* Before section */}
      <Sequence from={beforeStart} durationInFrames={beforeFrames}>
        <AbsoluteFill>
          {beforeImgSrc && (
            <Img
              src={beforeImgSrc}
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
              }}
            />
          )}
          <LabelOverlay
            label={before.label}
            description={before.description}
            brand={brand}
          />
        </AbsoluteFill>
      </Sequence>

      {/* Wipe transition */}
      <Sequence from={wipeStart} durationInFrames={wipeFrames}>
        <WipeTransition
          beforeSrc={beforeImgSrc}
          afterSrc={afterImgSrc}
          beforeLabel={before.label}
          afterLabel={after.label}
          brand={brand}
          durationFrames={wipeFrames}
        />
      </Sequence>

      {/* After section */}
      <Sequence from={afterStart} durationInFrames={afterFrames}>
        <AbsoluteFill>
          {afterImgSrc && (
            <Img
              src={afterImgSrc}
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
              }}
            />
          )}
          <LabelOverlay
            label={after.label}
            description={after.description}
            brand={brand}
          />
        </AbsoluteFill>
      </Sequence>

      {/* Side-by-side comparison */}
      <Sequence from={comparisonStart} durationInFrames={comparisonFrames}>
        <SideBySide
          beforeSrc={beforeImgSrc}
          afterSrc={afterImgSrc}
          beforeLabel={before.label}
          afterLabel={after.label}
          brand={brand}
        />
      </Sequence>

      <ProgressBar color={brand.colors.accent} />
      {logoSrc && <Logo src={logoSrc} width={80} position="bottom-right" />}
      {musicSrc && <Audio src={musicSrc} volume={0.3} />}
    </AbsoluteFill>
  );
};

/* ------------------------------------------------------------------ */
/* Internal sub-components                                            */
/* ------------------------------------------------------------------ */

interface LabelOverlayProps {
  label: string;
  description?: string;
  brand: ReturnType<typeof useBrandKit>;
}

const LabelOverlay: React.FC<LabelOverlayProps> = ({
  label,
  description,
  brand,
}) => {
  const frame = useCurrentFrame();

  const opacity = interpolate(frame, [0, 15], [0, 1], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  const translateY = interpolate(frame, [0, 15], [20, 0], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  return (
    <div
      style={{
        position: "absolute",
        bottom: 0,
        left: 0,
        right: 0,
        padding: "40px 60px",
        background: "rgba(0, 0, 0, 0.55)",
        opacity,
        transform: `translateY(${translateY}px)`,
      }}
    >
      <div
        style={{
          fontSize: 48,
          fontFamily: brand.fonts.heading,
          fontWeight: 700,
          color: brand.colors.text,
        }}
      >
        {label}
      </div>
      {description && (
        <div
          style={{
            fontSize: 28,
            fontFamily: brand.fonts.body,
            color: brand.colors.text,
            opacity: 0.8,
            marginTop: 8,
          }}
        >
          {description}
        </div>
      )}
    </div>
  );
};

interface WipeTransitionProps {
  beforeSrc: string | undefined;
  afterSrc: string | undefined;
  beforeLabel: string;
  afterLabel: string;
  brand: ReturnType<typeof useBrandKit>;
  durationFrames: number;
}

const WipeTransition: React.FC<WipeTransitionProps> = ({
  beforeSrc,
  afterSrc,
  beforeLabel,
  afterLabel,
  brand,
  durationFrames,
}) => {
  const frame = useCurrentFrame();

  const wipeProgress = interpolate(
    frame,
    [0, durationFrames],
    [0, 100],
    { extrapolateRight: "clamp", extrapolateLeft: "clamp" },
  );

  return (
    <AbsoluteFill>
      {/* Before image (full) */}
      {beforeSrc && (
        <Img
          src={beforeSrc}
          style={{
            position: "absolute",
            width: "100%",
            height: "100%",
            objectFit: "cover",
          }}
        />
      )}

      {/* After image (wiping in from left) */}
      {afterSrc && (
        <div
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            width: `${wipeProgress}%`,
            height: "100%",
            overflow: "hidden",
          }}
        >
          <Img
            src={afterSrc}
            style={{
              width: "100vw",
              height: "100%",
              objectFit: "cover",
            }}
          />
        </div>
      )}

      {/* Wipe divider line */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: `${wipeProgress}%`,
          width: 4,
          height: "100%",
          backgroundColor: brand.colors.accent,
        }}
      />
    </AbsoluteFill>
  );
};

interface SideBySideProps {
  beforeSrc: string | undefined;
  afterSrc: string | undefined;
  beforeLabel: string;
  afterLabel: string;
  brand: ReturnType<typeof useBrandKit>;
}

const SideBySide: React.FC<SideBySideProps> = ({
  beforeSrc,
  afterSrc,
  beforeLabel,
  afterLabel,
  brand,
}) => {
  const frame = useCurrentFrame();

  const opacity = interpolate(frame, [0, 15], [0, 1], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  const scale = interpolate(frame, [0, 15], [1.05, 1], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
  });

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "row",
        opacity,
        transform: `scale(${scale})`,
      }}
    >
      {/* Before half */}
      <div
        style={{
          width: "50%",
          height: "100%",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {beforeSrc && (
          <Img
            src={beforeSrc}
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
            }}
          />
        )}
        <div
          style={{
            position: "absolute",
            bottom: 40,
            left: 0,
            right: 0,
            textAlign: "center",
            fontSize: 32,
            fontFamily: brand.fonts.heading,
            fontWeight: 700,
            color: brand.colors.text,
            textShadow: "0 2px 8px rgba(0,0,0,0.6)",
          }}
        >
          {beforeLabel}
        </div>
      </div>

      {/* Divider */}
      <div
        style={{
          width: 4,
          height: "100%",
          backgroundColor: brand.colors.accent,
        }}
      />

      {/* After half */}
      <div
        style={{
          width: "50%",
          height: "100%",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {afterSrc && (
          <Img
            src={afterSrc}
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
            }}
          />
        )}
        <div
          style={{
            position: "absolute",
            bottom: 40,
            left: 0,
            right: 0,
            textAlign: "center",
            fontSize: 32,
            fontFamily: brand.fonts.heading,
            fontWeight: 700,
            color: brand.colors.text,
            textShadow: "0 2px 8px rgba(0,0,0,0.6)",
          }}
        >
          {afterLabel}
        </div>
      </div>
    </AbsoluteFill>
  );
};

export const calculateMetadata = async ({
  props,
}: {
  props: SocialBeforeAfterProps;
  defaultProps: SocialBeforeAfterProps;
}): Promise<{
  durationInFrames: number;
  fps: number;
  width: number;
  height: number;
}> => {
  const fps = 30;
  const titleSeconds = props.title ? 1.5 : 0;
  const totalSeconds = titleSeconds + 3 + 1 + 3 + 2; // title + before + wipe + after + comparison
  const durationInFrames = secondsToFrames(totalSeconds, fps);
  return { durationInFrames, fps, width: 1080, height: 1920 };
};

export const defaultProps: SocialBeforeAfterProps = {
  before: {
    label: "Before",
    image: "stock/placeholder-before.jpg",
    description: "The starting point",
  },
  after: {
    label: "After",
    image: "stock/placeholder-after.jpg",
    description: "The transformation",
  },
  title: "See the Difference",
  duration: 10,
};

